sys_ui_script.script:
function ShowNowAssistPanel(strConversationSysId) {
  (function () {
    function injectAndRunTop(fnText, callText) {
      var topDoc = window.top.document;

      // Versioned injection so you can iterate without stale code.
      var VERSION = "nowAssistPanelAutomation_v2_2026-02-23";
      if (window.top.__nowAssistPanelAutomationVersion !== VERSION) {
        var s = topDoc.createElement("script");
        s.type = "text/javascript";
        s.text =
          "window.__nowAssistPanelAutomationVersion=" +
          JSON.stringify(VERSION) +
          ";\n" +
          fnText;
        topDoc.head.appendChild(s);
      }

      var s2 = topDoc.createElement("script");
      s2.type = "text/javascript";
      s2.text = callText;
      topDoc.head.appendChild(s2);
    }

    var sysId =
      typeof strConversationSysId === "string" && /^[0-9a-f]{32}$/i.test(strConversationSysId)
        ? strConversationSysId
        : "";

    var TOP_RUNNER = String.raw`
(function(){
  var DEBUG = true;

  function ensureLogBuffer(){
    try{
      if(!window.__nowAssistDebugLogV2) window.__nowAssistDebugLogV2 = [];
      if(!window.__nowAssistDebugDumpV2){
        window.__nowAssistDebugDumpV2 = function(){
          try{
            console.log("[NowAssistPanelV2] --- DUMP (" + (window.__nowAssistDebugLogV2||[]).length + " entries) ---");
            (window.__nowAssistDebugLogV2||[]).forEach(function(x){ console.log.apply(console, x); });
          }catch(e){}
        };
      }
    }catch(e){}
  }

  function log(){
    if(!DEBUG) return;
    ensureLogBuffer();
    try{
      var args = Array.prototype.slice.call(arguments);
      args.unshift("[NowAssistPanelV2]");
      console.log.apply(console, args);
      window.__nowAssistDebugLogV2.push(args);
    }catch(e){}
  }

  function norm(s){
    var str = (s||"") + "";
    str = str.toLowerCase();
    str = str.replace(/\\s+/g," ");
    str = str.trim();
    return str;
  }

  function isSysId(s){
    return /^[0-9a-f]{32}$/i.test((s||"")+"");
  }

  function isVisible(el){
    if(!el) return false;
    try{
      var r=el.getBoundingClientRect();
      var s=getComputedStyle(el);
      return r.width>0 && r.height>0 && s.display!=="none" && s.visibility!=="hidden" && s.opacity!=="0";
    }catch(e){ return false; }
  }

  function describe(el){
    if(!el) return "(null)";
    try{
      var tag = (el.tagName||"").toLowerCase();
      var role = el.getAttribute && el.getAttribute("role");
      var label = el.getAttribute && el.getAttribute("aria-label");
      var title = el.getAttribute && el.getAttribute("title");
      var testid = el.getAttribute && (el.getAttribute("data-testid") || el.getAttribute("data-test-id"));
      var id = el.id;
      var cls = (typeof el.className==="string") ? el.className : "";
      return tag +
        (id ? "#"+id : "") +
        (cls ? "."+cls.split(/\\s+/).slice(0,3).join(".") : "") +
        (role ? " role="+role : "") +
        (label ? " aria-label="+label : "") +
        (title ? " title="+title : "") +
        (testid ? " testid="+testid : "");
    }catch(e){
      return "(unprintable element)";
    }
  }

  function buttonLike(el){
    if(!el || el.nodeType!==1) return false;
    var tag=(el.tagName||"").toLowerCase();
    var role=(el.getAttribute && el.getAttribute("role")) || "";
    return tag==="button" || role==="button" || (tag==="a" && role==="button") ||
      ((tag==="div"||tag==="span") && el.getAttribute && el.getAttribute("tabindex")!==null);
  }

  function realClick(el){
    if(!el) return false;
    try{
      // Some Now Experience components react better to real mouse events than .click()
      ["pointerdown","mousedown","pointerup","mouseup","click"].forEach(function(t){
        el.dispatchEvent(new MouseEvent(t, { bubbles:true, cancelable:true, view:window }));
      });
      return true;
    }catch(e){
      try{ el.click(); return true; }catch(e2){ return false; }
    }
  }

  // Deep walk: light DOM + OPEN shadow DOM + accessible iframes
  function deepWalkMultiRoot(doc, visitor, maxNodes){
    var q = [];
    if(doc && doc.body) q.push(doc.body);

    // Add iframe bodies when accessible (same-origin)
    try{
      var iframes = doc.querySelectorAll("iframe");
      for(var i=0;i<iframes.length;i++){
        try{
          var idoc = iframes[i].contentDocument;
          if(idoc && idoc.body) q.push(idoc.body);
        }catch(e){}
      }
    }catch(e){}

    var scanned=0;
    while(q.length && scanned<maxNodes){
      var n=q.shift(); scanned++;
      if(!n) continue;

      if(n.nodeType===1) visitor(n);

      if(n.children && n.children.length){
        for(var j=0;j<n.children.length;j++) q.push(n.children[j]);
      }
      if(n.shadowRoot) q.push(n.shadowRoot);
    }
  }

  // ---------- Panel detection (fixes your “panel visible but not detected” problem) ----------

  function isPinUnpinNowAssistButton(el){
    if(!buttonLike(el)) return false;
    var label = norm(el.getAttribute && el.getAttribute("aria-label"));
    var title = norm(el.getAttribute && el.getAttribute("title"));
    var text  = norm(el.textContent);
    var hay = (label+" "+title+" "+text).trim();
    return hay.indexOf("pin now assist") !== -1 || hay.indexOf("unpin now assist") !== -1;
  }

  function findPinUnpinButton(doc){
    var hit = null;
    deepWalkMultiRoot(doc, function(el){
      if(hit) return;
      if(!isVisible(el)) return;
      if(isPinUnpinNowAssistButton(el)) hit = el;
    }, 30000);
    if(hit) log("Found Pin/Unpin control (panel strong-signal):", describe(hit));
    return hit;
  }

  function looksLikeNowAssistPanelContainer(el){
    if(!el || el.nodeType!==1) return false;
    if(!isVisible(el)) return false;

    var role = norm(el.getAttribute && el.getAttribute("role"));
    var label = norm(el.getAttribute && el.getAttribute("aria-label"));
    var testid = norm((el.getAttribute && (el.getAttribute("data-testid") || el.getAttribute("data-test-id"))) || "");
    var cls = norm((typeof el.className==="string") ? el.className : "");
    var tag = norm(el.tagName || "");

    var roleMatch = (role === "dialog" || role === "complementary");
    var labelMatch = (label.indexOf("assist") !== -1 || label.indexOf("now assist") !== -1);
    var tidMatch = (testid.indexOf("assist") !== -1);
    var clsMatch = (cls.indexOf("assist") !== -1 || cls.indexOf("now-assist") !== -1);
    var tagMatch = (tag.indexOf("assist") !== -1);

    return (roleMatch && (labelMatch || tidMatch || clsMatch || tagMatch)) || tidMatch || (tagMatch && clsMatch);
  }

  function findVisiblePanelRoot(doc){
    var found = null;

    // 1) Try direct container-like elements via deep walk
    deepWalkMultiRoot(doc, function(el){
      if(found) return;
      if(looksLikeNowAssistPanelContainer(el)) found = el;
    }, 35000);

    if(found){
      log("Panel root detected via container heuristics:", describe(found));
      return found;
    }

    // 2) Fallback: if Pin/Unpin is visible, climb to a reasonable container
    var pinBtn = findPinUnpinButton(doc);
    if(pinBtn){
      var cur = pinBtn;
      for(var i=0; cur && i<20; i++){
        if(looksLikeNowAssistPanelContainer(cur)) {
          log("Panel root inferred by climbing from Pin/Unpin:", describe(cur));
          return cur;
        }
        cur = cur.parentElement;
      }
      // last resort: return the pin button parent chain top-ish
      log("Panel root fallback: using Pin/Unpin parent element:", describe(pinBtn.parentElement));
      return pinBtn.parentElement || pinBtn;
    }

    return null;
  }

  // ---------- Launcher detection (avoid picking Pin/Unpin as “launcher”) ----------

  function looksLikeNowAssistLauncher(el){
    if(!buttonLike(el)) return false;

    var label=norm(el.getAttribute && el.getAttribute("aria-label"));
    var title=norm(el.getAttribute && el.getAttribute("title"));
    var testid=norm(((el.getAttribute && el.getAttribute("data-testid"))||"") + " " +
                    ((el.getAttribute && el.getAttribute("data-test-id"))||""));
    var text=norm(el.textContent);
    var hay=(label+" "+title+" "+testid+" "+text).trim();

    // Exclude panel-internal controls that confused v1
    if(hay.indexOf("pin now assist") !== -1 || hay.indexOf("unpin now assist") !== -1) return false;

    // Prefer true launcher wording; keep generic fallback
    var hasNowAssist = hay.indexOf("now assist")!==-1 || hay.indexOf("nowassist")!==-1;
    var hasOpenClose = hay.indexOf("open now assist")!==-1 || hay.indexOf("close now assist")!==-1;
    var hasAssist = hay.indexOf("assist")!==-1;
    var hasNow = hay.indexOf("now")!==-1;

    return hasOpenClose || hasNowAssist || (hasAssist && hasNow) || (testid.indexOf("assist")!==-1);
  }

  function findNowAssistLauncher(doc){
    var candidates = [];
    deepWalkMultiRoot(doc, function(el){
      if(looksLikeNowAssistLauncher(el) && isVisible(el)) candidates.push(el);
    }, 35000);

    log("Launcher candidates (filtered, visible):", candidates.length);

    // Prefer "open/close now assist"
    for(var i=0;i<candidates.length;i++){
      var el=candidates[i];
      var hay = norm((el.getAttribute && el.getAttribute("aria-label"))||"") + " " +
                norm((el.getAttribute && el.getAttribute("title"))||"");
      if(hay.indexOf("open now assist")!==-1 || hay.indexOf("close now assist")!==-1){
        log("Picked launcher (open/close label):", describe(el));
        return el;
      }
    }

    // Otherwise first candidate
    if(candidates[0]) log("Picked launcher (first candidate):", describe(candidates[0]));
    return candidates[0] || null;
  }

  function ensurePanelOpen(doc){
    var panel = findVisiblePanelRoot(doc);
    if(panel){
      log("Panel considered OPEN (root found).");
      return true;
    }

    var btn = findNowAssistLauncher(doc);
    if(!btn){
      log("No launcher found; cannot open panel.");
      return false;
    }

    log("Panel not detected -> clicking launcher:", describe(btn));
    realClick(btn);
    return false; // allow retries to detect panel after render
  }

  // ---------- Conversation switching ----------

  function elementMentionsSysId(el, sysIdLower){
    if(!el || el.nodeType!==1) return false;

    var attrs=["data-conversation-id","data-conversationid","data-sys-id","data-sysid","data-id","id","href","value","name"];
    for(var i=0;i<attrs.length;i++){
      var v = el.getAttribute && el.getAttribute(attrs[i]);
      if(v && ((""+v).toLowerCase().indexOf(sysIdLower)!==-1)) return true;
    }

    try{
      if(el.dataset){
        for(var k in el.dataset){
          if(!Object.prototype.hasOwnProperty.call(el.dataset,k)) continue;
          var dv = (el.dataset[k]||"")+"";
          if(dv.toLowerCase().indexOf(sysIdLower)!==-1) return true;
        }
      }
    }catch(e){}

    return false;
  }

  function findConversationClickableBySysId(root, sysId){
    var sysIdLower = (sysId||"").toLowerCase();
    var hit = null;

    // Scan deep under the given root (including shadow)
    var doc = window.document;
    deepWalkMultiRoot(doc, function(el){
      if(hit) return;
      if(root && el !== root && !root.contains(el)) return;
      if(!isVisible(el)) return;
      if(elementMentionsSysId(el, sysIdLower)){
        hit = el;
        // climb to clickable
        var cur = el;
        for(var i=0; cur && i<10; i++){
          if(buttonLike(cur)) { hit = cur; break; }
          cur = cur.parentElement;
        }
      }
    }, 50000);

    log("Conversation sys_id scan hit:", hit ? describe(hit) : "(none)");
    return hit;
  }

  function looksLikeChatsControl(el){
    if(!buttonLike(el)) return false;
    var label=norm(el.getAttribute && el.getAttribute("aria-label"));
    var title=norm(el.getAttribute && el.getAttribute("title"));
    var testid=norm(((el.getAttribute && el.getAttribute("data-testid"))||"") + " " +
                    ((el.getAttribute && el.getAttribute("data-test-id"))||""));
    var text=norm(el.textContent);
    var hay=(label+" "+title+" "+testid+" "+text).trim();

    // “Chats” is the standard label for the control that opens “All chats”
    if(hay.indexOf("chats") !== -1) return true;
    if(hay.indexOf("all chats") !== -1) return true;
    if(testid.indexOf("chat") !== -1) return true;
    return false;
  }

  function findChatsControl(panelRoot){
    var found = null;
    var doc = window.document;

    deepWalkMultiRoot(doc, function(el){
      if(found) return;
      if(panelRoot && el !== panelRoot && !panelRoot.contains(el)) return;
      if(!isVisible(el)) return;
      if(looksLikeChatsControl(el)) found = el;
    }, 30000);

    log("Chats/All chats control:", found ? describe(found) : "(not found)");
    return found;
  }

  function sampleAnySysIdLikeValuesWithin(panelRoot){
    var hits = [];
    var re = /[0-9a-f]{32}/ig;
    var doc = window.document;

    deepWalkMultiRoot(doc, function(el){
      if(hits.length>=15) return;
      if(panelRoot && el !== panelRoot && !panelRoot.contains(el)) return;

      try{
        if(el.attributes){
          for(var i=0;i<el.attributes.length && hits.length<15;i++){
            var a = el.attributes[i];
            if(!a || !a.value) continue;
            var m = (a.value+"").match(re);
            if(m && m.length){
              hits.push({where:"attr:"+a.name, value:m[0], el: describe(el)});
            }
          }
        }
      }catch(e){}

      try{
        if(el.dataset){
          for(var k in el.dataset){
            if(hits.length>=15) break;
            var dv = (el.dataset[k]||"")+"";
            var md = dv.match(re);
            if(md && md.length){
              hits.push({where:"dataset:"+k, value:md[0], el: describe(el)});
            }
          }
        }
      }catch(e){}
    }, 60000);

    return hits;
  }

  function trySelectConversation(sysId){
    if(!isSysId(sysId)) {
      log("No valid sys_id provided -> selection skipped.");
      return true;
    }

    var doc = window.document;
    var panelRoot = findVisiblePanelRoot(doc);
    if(!panelRoot){
      log("Panel root not detected yet -> cannot select conversation.");
      return false;
    }

    // Ensure chat list is open (Chats icon -> All chats)
    var chatsBtn = findChatsControl(panelRoot);
    if(chatsBtn){
      log("Clicking Chats/All chats control:", describe(chatsBtn));
      realClick(chatsBtn);
    } else {
      log("No Chats control found; will still attempt sys_id scan in panel.");
    }

    // Try to find a clickable element that contains the sys_id
    var target = findConversationClickableBySysId(panelRoot, sysId) || findConversationClickableBySysId(doc.body, sysId);
    if(target){
      log("Clicking conversation target:", describe(target));
      realClick(target);
      return true;
    }

    // Diagnostics: do we see ANY sys_id-like values inside the panel?
    var samples = sampleAnySysIdLikeValuesWithin(panelRoot);
    if(samples && samples.length){
      log("Found sys_id-like values inside panel (sample up to 15):", samples);
    } else {
      log("No sys_id-like values found inside panel. UI may not expose sys_id in DOM (or uses closed shadow DOM).");
    }

    return false;
  }

  window.nowAssistOpenAndSelectConversationV2 = function(conversationSysId){
    ensureLogBuffer();
    window.__nowAssistTargetConversationSysIdV2 = isSysId(conversationSysId) ? conversationSysId : "";
    log("Invocation target sys_id:", window.__nowAssistTargetConversationSysIdV2 || "(none)");

    var tries=0, max=50;
    var t=setInterval(function(){
      tries++;

      var openOk = ensurePanelOpen(window.document);
      var target = window.__nowAssistTargetConversationSysIdV2;

      if(!target){
        if(openOk || tries>=max){
          log("Done (no target). tries:", tries);
          clearInterval(t);
        }
        return;
      }

      var ok = trySelectConversation(target);

      if(ok || tries>=max){
        log("Done. ok:", ok, "tries:", tries);
        clearInterval(t);
      }
    }, 250);
  };
})();`;

    injectAndRunTop(
      TOP_RUNNER,
      "window.nowAssistOpenAndSelectConversationV2 && window.nowAssistOpenAndSelectConversationV2(" +
        JSON.stringify(sysId) +
        ");"
    );
  })();
}
